def func_q(m_2, m_1, x_1_0, y_1_0, x_2_0, y_2_0, v_x1_0, v_y1_0, v_x2_0, v_y2_0, t_final):
    def f(t, q):
        return [q[4], q[5], q[6], q[7], -6.6743e-11 * m_2 * (q[0] - q[2]) / math.sqrt((q[0] - q[2]) ** 2.0 + (q[1] - q[3]) ** 2.0) ** 3.0, -6.6743e-11 * m_2 * (q[1] - q[3]) / math.sqrt((q[0] - q[2]) ** 2.0 + (q[1] - q[3]) ** 2.0) ** 3.0, 6.6743e-11 * m_1 * (q[0] - q[2]) / math.sqrt((q[0] - q[2]) ** 2.0 + (q[1] - q[3]) ** 2.0) ** 3.0, 6.6743e-11 * m_1 * (q[1] - q[3]) / math.sqrt((q[0] - q[2]) ** 2.0 + (q[1] - q[3]) ** 2.0) ** 3.0]
    
    r = scipy.integrate.ode(f)
    r.set_integrator("dopri5", atol=1.0e-8, rtol=1.0e-8)
    r.set_initial_value([x_1_0, y_1_0, x_2_0, y_2_0, v_x1_0, v_y1_0, v_x2_0, v_y2_0], 0.0)
